  ensureLesson('Sales', 'Sandler Selling');
  LESSON_QUESTIONS['Sales']['Sandler Selling'] = [
    { type: 'multiple_choice', prompt: 'What is the Sandler Selling System best known for?', options: ['Aggressive hard-closing techniques', 'A buyer-seller relationship where the salesperson acts as an equal partner, not a subservient vendor', 'Discounting strategies', 'Cold email templates'], correctAnswer: 'A buyer-seller relationship where the salesperson acts as an equal partner, not a subservient vendor', difficulty: 'easy', explanation: 'Sandler flips the traditional power dynamic. Instead of chasing prospects, you qualify them as rigorously as they evaluate you.' },
    { type: 'multiple_choice', prompt: 'What is the "Sandler Submarine" concept?', options: ['A sales competition', 'A seven-step selling process that moves through compartments, each sealed before advancing to the next', 'An underwater sales retreat', 'A CRM feature'], correctAnswer: 'A seven-step selling process that moves through compartments, each sealed before advancing to the next', difficulty: 'medium', explanation: 'Like a submarine sealing compartments, each Sandler step must be completed before moving forward, preventing deals from sliding backward.' },
    { type: 'true_false', prompt: 'In the Sandler system, the salesperson should never reveal their pricing until the prospect\'s pain and budget have been fully explored.', options: ['True', 'False'], correctAnswer: 'True', difficulty: 'medium', explanation: 'Sandler teaches that presenting price before establishing pain and budget leads to sticker shock. Build value and confirm budget fit first.' },
    { type: 'fill_gap', prompt: 'Sandler\'s "up-front ___" sets clear expectations for both parties at the start of every meeting, covering agenda, time, and outcomes.', options: ['Contract', 'Discount', 'Pitch', 'Email'], correctAnswer: 'Contract', difficulty: 'easy', explanation: 'The up-front contract eliminates ambiguity by agreeing on what will happen during and after the meeting, including the right to say no.' },
    { type: 'multiple_choice', prompt: 'What is the "pain funnel" in Sandler selling?', options: ['A marketing funnel for pain relief products', 'A series of progressively deeper questions that uncover the emotional and financial impact of the prospect\'s problem', 'A physical funnel used in demonstrations', 'A complaint tracking system'], correctAnswer: 'A series of progressively deeper questions that uncover the emotional and financial impact of the prospect\'s problem', difficulty: 'hard', explanation: 'The pain funnel moves from surface questions ("Tell me more") to deep emotional questions ("How has this affected you personally?"), connecting business pain to personal motivation.' },
    { type: 'true_false', prompt: 'Sandler encourages salespeople to tell prospects "it is okay to say no" to reduce pressure and build honesty.', options: ['True', 'False'], correctAnswer: 'True', difficulty: 'easy', explanation: 'Giving permission to say no paradoxically makes prospects more honest and open, leading to better qualification and more genuine conversations.' },
    { type: 'multiple_choice', prompt: 'What does "reversing" mean in Sandler selling?', options: ['Going backward in the sales process', 'Answering a question with a question to maintain control and uncover the real concern behind the prospect\'s question', 'Reversing a refund', 'Changing your product offering'], correctAnswer: 'Answering a question with a question to maintain control and uncover the real concern behind the prospect\'s question', difficulty: 'medium', explanation: 'When a prospect asks "Does it integrate with Salesforce?" a reverse might be "That sounds important to you — what happens if it does not?" This reveals the weight of the requirement.' },
    { type: 'true_false', prompt: 'In Sandler selling, the prospect should do most of the talking while the salesperson guides with questions.', options: ['True', 'False'], correctAnswer: 'True', difficulty: 'easy', explanation: 'Sandler is a questioning-based methodology. The salesperson asks and listens while the prospect reveals their pain, budget, and decision process.' },
  ];

